let text = $json.output || "";

// Clean raw text
text = text.replace(/\\n/g, '\n').trim();

// Extract sections safely
const summaryMatch = text.match(/Market Summary\s*:\s*([\s\S]*?)(?=Key Movers\s*:|$)/i);
const moversMatch = text.match(/Key Movers\s*:\s*([\s\S]*?)(?=Risk Sentiment\s*:|Actionable Insight\s*:|$)/i);
const sentimentMatch = text.match(/Risk Sentiment\s*:\s*([\s\S]*?)(?=Actionable Insight\s*:|$)/i);
const insightMatch = text.match(/Actionable Insight\s*:\s*([\s\S]*?)(?=Outlook\s*:|$)/i);
const outlookMatch = text.match(/Outlook\s*:\s*([\s\S]*)/i);

// Assign values
let summary = summaryMatch?.[1] || "";
let moversRaw = moversMatch?.[1] || "";
let sentiment = sentimentMatch?.[1] || "";
let insight = insightMatch?.[1] || "";
let outlook = outlookMatch?.[1] || "";

// Common cleanup
const cleanText = (t) => {
  if (!t) return "";

  return t
    .replace(/\*\*/g, "")
    .replace(/\s+/g, " ")
    .trim();
};

summary = cleanText(summary);
sentiment = cleanText(sentiment);
insight = cleanText(insight);
outlook = cleanText(outlook);

// Clean movers list
const movers = moversRaw
  .split(/\r?\n+/)
  .map(line =>
    line
      .replace(/^[-*•]\s*/, "")
      .replace(/\s+/g, " ")
      .trim()
  )
  .filter(Boolean);

// FIXED sentence trim (safe for decimals like 1.46%)
const trimToTwoSentences = (text) => {
  if (!text) return "";

  const sentences =
    text.match(/(?:[^.!?]|\d\.\d)+[.!?]+/g) || [text];

  return sentences
    .slice(0, 2)
    .join(" ")
    .trim();
};

summary = trimToTwoSentences(summary);
insight = trimToTwoSentences(insight);
outlook = trimToTwoSentences(outlook);

// Final output
return [
  {
    json: {
      market_summary: summary,
      key_movers: movers,
      risk_sentiment: sentiment,
      insight,
      outlook
    }
  }
];

