return [
  {
    json: {
      error_time: new Date().toISOString(),
      error_status: $json.status,
      error_message: $json.message || "Unknown API error",
      failed_symbol: $json.meta?.symbol || "N/A"
    }
  }
];

const result = [];
let runIndex = 0;

// Loop through every execution run of the Fetch node
while (true) {
  try {
    // Grab the data for the specific loop iteration
    const rawData = $items("Fetch Asset Prices", 0, runIndex);

    // Break if we've reached the end of the runs
    if (!rawData || rawData.length === 0) break;

    for (const item of rawData) {
      const data = item.json;
      const latest = data.values?.[0];

      // If data is missing (e.g. rate limit hit), record the error instead of skipping
      if (!latest) {
        result.push({
          symbol: data.meta?.symbol || data.symbol || "Unknown",
          status: data.status || "error",
          message: data.message || "No data received (likely rate limit)"
        });
        continue;
      }

      const open = parseFloat(latest.open);
      const close = parseFloat(latest.close);
      const changePercent = ((close - open) / open) * 100;

      result.push({
        symbol: data.meta.symbol,
        asset_type: data.meta.type,
        price: close,
        open,
        high: parseFloat(latest.high),
        low: parseFloat(latest.low),
        date: latest.datetime,
        change_percent: Number(changePercent.toFixed(2)),
        trend: changePercent > 0 ? "Bullish" : "Bearish",
        status: "success"
      });
    }
    runIndex++; // Move to the next execution run
  } catch (error) {
    // When runIndex exceeds the total number of runs, it throws an error. Break the loop.
    break;
  }
}

return [
  {
    json: {
      market_data: result
    }
  }
];

const data = items[0].json;
const output = [];

// Define all asset classes
const assetGroups = [
  { asset_class: "Indices", symbols: data.Indices },
  { asset_class: "Forex", symbols: data.Forex },
  { asset_class: "Commodities", symbols: data.Commodities }
];

// Split each asset group into individual symbols
for (const group of assetGroups) {
  const symbols = group.symbols.split(',');

  for (const symbol of symbols) {
    output.push({
      json: {
        asset_class: group.asset_class,
        symbol: symbol.trim()
      }
    });
  }
}

return output;
